module adder_pipe_64bit (
    input clk,
    input rst_n,
    input i_en,
    input [63:0] adda,
    input [63:0] addb,
    output reg [64:0] result,
    output reg o_en
);

    reg [63:0] adda_reg, addb_reg;
    reg i_en_reg;
    reg [64:0] sum_reg;
    reg [64:0] sum_reg1, sum_reg2, sum_reg3;
    reg o_en_reg;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            adda_reg <= 0;
            addb_reg <= 0;
            i_en_reg <= 0;
            sum_reg <= 0;
            sum_reg1 <= 0;
            sum_reg2 <= 0;
            sum_reg3 <= 0;
            o_en_reg <= 0;
        end else begin
            adda_reg <= adda;
            addb_reg <= addb;
            i_en_reg <= i_en;
            sum_reg <= adda_reg + addb_reg;
            sum_reg1 <= sum_reg;
            sum_reg2 <= sum_reg1;
            sum_reg3 <= sum_reg2;
            o_en_reg <= i_en_reg;
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            result <= 0;
            o_en <= 0;
        end else begin
            result <= sum_reg3;
            o_en <= o_en_reg;
        end
    end

endmodule

